function solve(points: number[][]): number {
    const MOD = 10**9 + 7;
    const n = points.length;
    const yMap = new Map<number, number[]>();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!yMap.has(y)) {
            yMap.set(y, []);
        }
        yMap.get(y)!.push(x);
    }

    let result = 0;

    // For each y-coordinate, process the x-values
    for (const [y, xs] of yMap.entries()) {
        const m = xs.length;
        if (m < 2) continue;

        // Sort x-values for easier processing
        xs.sort((a, b) => a - b);

        // Count the number of pairs of points at the same y-coordinate
        let sameYPairs = 0;
        for (let i = 0; i < m; i++) {
            for (let j = i + 1; j < m; j++) {
                sameYPairs++;
            }
        }

        // For each pair of points at the same y-coordinate, find pairs at another y-coordinate
        for (const [otherY, otherXs] of yMap.entries()) {
            if (otherY === y) continue;

            const k = otherXs.length;
            if (k < 2) continue;

            // Sort other x-values
            otherXs.sort((a, b) => a - b);

            // Count the number of pairs of points at the other y-coordinate
            let sameOtherYPairs = 0;
            for (let i = 0; i < k; i++) {
                for (let j = i + 1; j < k; j++) {
                    sameOtherYPairs++;
                }
            }

            // For each pair of points at the same y-coordinate and each pair at the other y-coordinate,
            // form a trapezoid with these four points
            result += sameYPairs * sameOtherYPairs;
            result %= MOD;
        }
    }

    return result;
}

